27: import java.nio.charset.Charset;
28: import java.util.Arrays;
29: 
30: /**
31:  * Input Format that reads text files. Each line results in another element.
32:  *
33:  * @deprecated If you want to read/write data from/to text file, please use FLIP-27 FileSource and
34:  *     Sink-V2 FlinkSink. This class should be removed if we drop the supports for read/write via
35:  *     input/output format in DataStream api.
36:  */
37: @Deprecated
38: @PublicEvolving
39: public class TextInputFormat extends DelimitedInputFormat<String> {
40: 
41:     private static final long serialVersionUID = 1L;
42: 
43:     /** Code of \r, used to remove \r from a line when the line ends with \r\n. */
44:     private static final byte CARRIAGE_RETURN = (byte) '\r';
45: 
46:     /** Code of \n, used to identify if \n is used as delimiter. */
47:     private static final byte NEW_LINE = (byte) '\n';
48: 
49:     /** The name of the charset to use for decoding. */
50:     private String charsetName = "UTF-8";
51: 
52:     // --------------------------------------------------------------------------------------------
53: 
54:     public TextInputFormat(Path filePath) {
55:         super(filePath, null);
56:     }
57: 
58:     // --------------------------------------------------------------------------------------------
59: 
60:     public String getCharsetName() {
61:         return charsetName;
62:     }
63: 
64:     public void setCharsetName(String charsetName) {
65:         if (charsetName == null) {
66:             throw new IllegalArgumentException("Charset must not be null.");
67:         }
68: 
69:         this.charsetName = charsetName;
70:     }
71: 
72:     // --------------------------------------------------------------------------------------------
73: 
74:     @Override
75:     public void configure(Configuration parameters) {
76:         super.configure(parameters);
77: 
78:         if (charsetName == null || !Charset.isSupported(charsetName)) {
79:             throw new RuntimeException("Unsupported charset: " + charsetName);
80:         }
81:     }
82: 
83:     // --------------------------------------------------------------------------------------------
84: 
85:     @Override
86:     public String readRecord(String reusable, byte[] bytes, int offset, int numBytes)
87:             throws IOException {
88:         // Check if \n is used as delimiter and the end of this line is a \r, then remove \r from
89:         // the line
90:         if (this.getDelimiter() != null
91:                 && this.getDelimiter().length == 1
92:                 && this.getDelimiter()[0] == NEW_LINE
93:                 && offset + numBytes >= 1
94:                 && bytes[offset + numBytes - 1] == CARRIAGE_RETURN) {
95:             numBytes -= 1;
96:         }
97: 
98:         return new String(bytes, offset, numBytes, this.charsetName);
99:     }
100: 
101:     // --------------------------------------------------------------------------------------------
102: 
103:     @Override
104:     public String toString() {
105:         return "TextInputFormat (" + Arrays.toString(getFilePaths()) + ") - " + this.charsetName;
106:     }
107: }
